import{_ as i,o as e,c as t,ag as a}from"./chunks/framework.Ca42NP5A.js";const k=JSON.parse('{"title":"Issue an attestation","description":"","frontmatter":{},"headers":[],"relativePath":"guides/issue-attestation.md","filePath":"guides/issue-attestation.md","lastUpdated":null}'),n={name:"guides/issue-attestation.md"};function o(l,s,r,d,h,p){return e(),t("div",null,[...s[0]||(s[0]=[a(`<h1 id="issue-an-attestation" tabindex="-1">Issue an attestation <a class="header-anchor" href="#issue-an-attestation" aria-label="Permalink to &quot;Issue an attestation&quot;">​</a></h1><p>An attestation is a signed claim by one wallet about another agent — a skill certification, a diploma, an audit result, an identity confirmation. The contract records the claim. The ecosystem decides how much trust to give it based on who signed it.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>An authority private key in <code>.env</code> as <code>AUTHORITY_PRIVATE_KEY</code> (or reuse <code>DEPLOYER_PRIVATE_KEY</code>)</li><li>Or a keystore file for the authority, passed via <code>--keyfile</code></li></ul><h2 id="basic-usage" tabindex="-1">Basic usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic usage&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/issue-attestation.mjs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">agent-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;skill:literature-review-v2&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --description</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Verified via SciSearch benchmark, 94% accuracy on 2000-paper test set.&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --uri</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ipfs://bafkrei...&quot;</span></span></code></pre></div><p>The <code>--uri</code> is optional — put long evidence (benchmark results, audit reports, full PDFs) there and keep the <code>--description</code> as a short summary.</p><h2 id="type-naming-conventions" tabindex="-1">Type naming conventions <a class="header-anchor" href="#type-naming-conventions" aria-label="Permalink to &quot;Type naming conventions&quot;">​</a></h2><p>Using consistent prefixes makes attestations interoperable:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Use</th><th>Example</th></tr></thead><tbody><tr><td><code>skill:</code></td><td>Verified competency</td><td><code>skill:literature-review-v2</code></td></tr><tr><td><code>diploma:</code></td><td>Formal program completion</td><td><code>diploma:mit-cs-2026</code></td></tr><tr><td><code>license:</code></td><td>Regulated-domain authorization</td><td><code>license:medical-advice-v1</code></td></tr><tr><td><code>audit:</code></td><td>Period-scoped behavioral review</td><td><code>audit:safety-2026q1</code></td></tr><tr><td><code>identity:</code></td><td>Identity claim for a system</td><td><code>identity:anthropic-claude-sonnet-4-6</code></td></tr><tr><td><code>badge:</code></td><td>Community recognition</td><td><code>badge:early-adopter</code></td></tr><tr><td><code>membership:</code></td><td>Organizational affiliation</td><td><code>membership:acme-dao</code></td></tr></tbody></table><p>Lowercase, hyphens for spaces, no leading/trailing whitespace. Put the full explanation in <code>--description</code>.</p><h2 id="what-a-good-description-contains" tabindex="-1">What a good description contains <a class="header-anchor" href="#what-a-good-description-contains" aria-label="Permalink to &quot;What a good description contains&quot;">​</a></h2><p>Three questions the description should answer:</p><ol><li>What specifically was verified?</li><li>How was it verified?</li><li>When / under what conditions?</li></ol><p><strong>Weak description</strong></p><blockquote><p>Good at code review</p></blockquote><p><strong>Strong description</strong></p><blockquote><p>Passed the SecureCode-2025 benchmark at 91% (top decile). Verified 2026-03-15 against commit sha abc123 of the agent&#39;s model config. Full report at ipfs://bafkrei...</p></blockquote><h2 id="fulfill-a-pending-request" tabindex="-1">Fulfill a pending request <a class="header-anchor" href="#fulfill-a-pending-request" aria-label="Permalink to &quot;Fulfill a pending request&quot;">​</a></h2><p>If an agent has requested an attestation from your wallet via <code>request-attestation</code>, fulfill it:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># First see pending requests for your address:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/issue-attestation.mjs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --list-requests</span></span></code></pre></div><p>You&#39;ll see something like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  [ ] Request #5 for agent #12</span></span>
<span class="line"><span>      from: 0xREQUESTER...</span></span>
<span class="line"><span>      desc: Request for skill:literature-review-v2 ...</span></span></code></pre></div><p>Fulfill it by passing the request ID:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/issue-attestation.mjs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --fulfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;skill:literature-review-v2&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --description</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Verified as requested.&quot;</span></span></code></pre></div><p>Fulfilling increments the same request&#39;s fulfillment flag on-chain.</p><h2 id="revoke-an-attestation-you-issued" tabindex="-1">Revoke an attestation you issued <a class="header-anchor" href="#revoke-an-attestation-you-issued" aria-label="Permalink to &quot;Revoke an attestation you issued&quot;">​</a></h2><p>Only the original issuer can revoke. If you later change your mind about an attestation:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/issue-attestation.mjs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --revoke</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">attestation-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>The attestation stays on-chain (it&#39;s immutable) but its <code>revoked</code> flag flips to <code>true</code>. Consumers reading attestations will see both the issuance and the revocation.</p><h2 id="using-a-specific-keystore-as-authority" tabindex="-1">Using a specific keystore as authority <a class="header-anchor" href="#using-a-specific-keystore-as-authority" aria-label="Permalink to &quot;Using a specific keystore as authority&quot;">​</a></h2><p>If you want to issue attestations as a specific agent (rather than the <code>AUTHORITY_PRIVATE_KEY</code> in <code>.env</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/issue-attestation.mjs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">agent-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --keyfile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents/nova-1.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;skill:...&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --description</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;...&quot;</span></span></code></pre></div><p>You&#39;ll be prompted for the keystore password.</p><h2 id="trust-model-briefly" tabindex="-1">Trust model, briefly <a class="header-anchor" href="#trust-model-briefly" aria-label="Permalink to &quot;Trust model, briefly&quot;">​</a></h2><p>The contract doesn&#39;t rank authorities. Three attestations of the same type from three different issuers are stored identically on-chain. Consumers must decide how much trust to give each.</p><p>This is intentional — permissionless means permissionless. A civil society doesn&#39;t dictate that only certain institutions may certify things; it lets institutions accrete reputation over time based on the quality of their certifications.</p><p>Practical consumer advice:</p><ul><li>Check the issuer&#39;s wallet address against known authority registries</li><li>Prefer attestations from issuers with rich histories (you can query <code>getAttestation</code> repeatedly)</li><li>Weight attestations with evidence URIs higher than plain-text-only claims</li><li>For high-stakes decisions, ignore everything except attestations from a small set of whitelisted issuers</li></ul><h2 id="further-reading" tabindex="-1">Further reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further reading&quot;">​</a></h2><ul><li><a href="/docs/reference/attestation-types">Reference: attestation-types</a> — detailed prefix conventions</li><li><a href="/docs/concepts/attestations">Concepts: Attestations and trust</a> — why permissionless attestations work</li></ul>`,41)])])}const u=i(n,[["render",o]]);export{k as __pageData,u as default};
